+export function sequenceMaybeAsResult<T extends {}, E>(errValue: E): (maybes: Iterable<Maybe<T>>) => Result<T[], E>;
+export function sequenceMaybeAsResult<T extends {}, E>(errValue: E, maybes?: Iterable<Maybe<T>>) {
+  const op = (items: Iterable<Maybe<T>>): Result<T[], E> => {
+    const values: T[] = [];
+    for (const maybe of items) {
+      if (maybe.isNothing) return Result.err<T[], E>(errValue);
+      values.push(maybe.value);
+    }
+    return Result.ok<T[], E>(values);
+  };
+  return maybes === undefined ? op : op(maybes);
+}
+
+/** Traverse items as `Maybe`s, converting the first `Nothing` to `Err(errValue)`. */
+export function traverseMaybeAsResult<T, U extends {}, E>(errValue: E, items: Iterable<T>, fn: (item: T) => Maybe<U>): Result<U[], E>;
+export function traverseMaybeAsResult<T, U extends {}, E>(errValue: E): (items: Iterable<T>, fn: (item: T) => Maybe<U>) => Result<U[], E>;
+export function traverseMaybeAsResult<T, U extends {}, E>(errValue: E, items?: Iterable<T>, maybeFn?: (item: T) => Maybe<U>) {
+  const op = (values: Iterable<T>, fn: (item: T) => Maybe<U>): Result<U[], E> => {
+    const output: U[] = [];
+    for (const item of values) {
+      const maybe = fn(item);
+      if (maybe.isNothing) return Result.err<U[], E>(errValue);
+      output.push(maybe.value);
+    }
+    return Result.ok<U[], E>(output);
+  };
+  return items === undefined ? op : op(items, maybeFn!);
+}
+
+/** Combine two `Maybe`s as a `Result`, converting `Nothing` to `Err(errValue)`. */
+export function zipMaybeAsResult<A extends {}, B extends {}, E>(errValue: E, a: Maybe<A>, b: Maybe<B>): Result<[A, B], E>;
+export function zipMaybeAsResult<A extends {}, B extends {}, E>(errValue: E): (a: Maybe<A>, b: Maybe<B>) => Result<[A, B], E>;
+export function zipMaybeAsResult<A extends {}, B extends {}, E>(errValue: E, a?: Maybe<A>, b?: Maybe<B>) {
+  const op = (left: Maybe<A>, right: Maybe<B>): Result<[A, B], E> =>
+    left.isJust && right.isJust ? Result.ok<[A, B], E>([left.value, right.value]) : Result.err<[A, B], E>(errValue);
